    """Base exception for the application."""
    def __init__(self, code: str, message: str, status_code: int = 400):
        self.code = code
        self.message = message
        self.status_code = status_code

class ItemNotFoundError(AppException):
    def __init__(self, item_id: int):
        super().__init__(
            code="ITEM_NOT_FOUND",
            message=f"Item {item_id} does not exist",
            status_code=404,
        )
        self.item_id = item_id

class InsufficientStockError(AppException):
    def __init__(self, item_id: int, available: int):
        super().__init__(
            code="INSUFFICIENT_STOCK",
            message=f"Only {available} units available",
            status_code=409,
        )

# --- Register handler for the base exception class ---
@app.exception_handler(AppException)
async def app_exception_handler(request: Request, exc: AppException):
    return JSONResponse(
        status_code=exc.status_code,
        content={
            "error": {
                "code": exc.code,
                "message": exc.message,
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "path": str(request.url.path),
            }
        },
    )

