from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from fastapi.testclient import TestClient

app = FastAPI()

# --- Exception hierarchy ---
class AppException(Exception):
    """Base exception for all application errors."""
    def __init__(self, code: str, message: str, status_code: int = 400, details: dict | None = None):
        self.code = code
        self.message = message
        self.status_code = status_code
        self.details = details or {}
        super().__init__(message)

class NotFoundError(AppException):
    def __init__(self, resource: str, resource_id: int | str):
        super().__init__(
            code=f"{resource.upper()}_NOT_FOUND",
            message=f"{resource.capitalize()} '{resource_id}' does not exist",
            status_code=404,
            details={"resource": resource, "id": resource_id},
        )

class ConflictError(AppException):
    def __init__(self, resource: str, field: str, value: str):
        super().__init__(
            code=f"DUPLICATE_{field.upper()}",
            message=f"{resource.capitalize()} with {field}='{value}' already exists",
            status_code=409,
            details={"field": field, "value": value},
        )

class BusinessRuleError(AppException):
    def __init__(self, code: str, message: str, details: dict | None = None):
        super().__init__(code=code, message=message, status_code=422, details=details)

# --- Single handler for all AppExceptions ---
@app.exception_handler(AppException)
async def app_exception_handler(request: Request, exc: AppException):
    return JSONResponse(
        status_code=exc.status_code,
        content={
            "error": {
                "code": exc.code,
                "message": exc.message,
                "details": exc.details,
            }
        },
    )

# --- Usage in endpoints ---
USERS = {"alice@example.com": {"id": 1, "name": "Alice", "email": "alice@example.com"}}

@app.get("/users/{user_id}")
def get_user(user_id: int):
    raise NotFoundError(resource="user", resource_id=user_id)

@app.post("/users")
def create_user(email: str = "alice@example.com"):
    if email in USERS:
        raise ConflictError(resource="user", field="email", value=email)
    return {"created": email}

@app.post("/transfer")
def transfer(amount: float = 100, balance: float = 50):
    if amount > balance:
        raise BusinessRuleError(
            code="INSUFFICIENT_FUNDS",
            message=f"Cannot transfer ${amount}: only ${balance} available",
            details={"required": amount, "available": balance},
        )
    return {"transferred": amount}

# --- Test ---
client = TestClient(app)

# Not found
resp = client.get("/users/42")
print(f"404: {resp.json()['error']['code']} - {resp.json()['error']['message']}")

# Conflict
resp = client.post("/users?email=alice@example.com")
print(f"409: {resp.json()['error']['code']}")

# Business rule
resp = client.post("/transfer?amount=100&balance=50")
err = resp.json()["error"]
print(f"422: {err['code']} - {err['details']}")

# Expected Output:
# 404: USER_NOT_FOUND - User '42' does not exist
# 409: DUPLICATE_EMAIL
# 422: INSUFFICIENT_FUNDS - {'required': 100.0, 'available': 50.0}

