import logging
import uuid
from fastapi import FastAPI, Request, HTTPException
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from fastapi.testclient import TestClient
from starlette.exceptions import HTTPException as StarletteHTTPException

logging.basicConfig(level=logging.INFO, format="%(levelname)s: %(message)s")
logger = logging.getLogger("api")

app = FastAPI()

# --- Specific handlers first ---
@app.exception_handler(StarletteHTTPException)
async def http_exception_handler(request: Request, exc: StarletteHTTPException):
    return JSONResponse(
        status_code=exc.status_code,
        content={"error": {"code": f"HTTP_{exc.status_code}", "message": str(exc.detail)}},
    )

@app.exception_handler(RequestValidationError)
async def validation_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content={"error": {"code": "VALIDATION_FAILED", "message": "Invalid request data"}},
    )

# --- Global catch-all (runs LAST, only for unhandled exceptions) ---
@app.exception_handler(Exception)
async def global_exception_handler(request: Request, exc: Exception):
    request_id = str(uuid.uuid4())[:8]

    # Full details logged server-side
    logger.error(
        f"[{request_id}] Unhandled {type(exc).__name__} "
        f"on {request.method} {request.url.path}: {exc}"
    )

    # Safe response to client -- no internal details
    return JSONResponse(
        status_code=500,
        content={
            "error": {
                "code": "INTERNAL_ERROR",
                "message": "An unexpected error occurred. Please try again later.",
                "request_id": request_id,
            }
        },
    )

# --- Endpoints ---
@app.get("/ok")
def ok():
    return {"status": "ok"}

@app.get("/not-found")
def not_found():
    raise HTTPException(status_code=404, detail="Resource not found")

@app.get("/crash")
def crash():
    # Simulates an unexpected bug
    result = 1 / 0  # noqa: F841
    return {"result": result}

@app.get("/key-error")
def key_error():
    data = {}
    return data["missing_key"]

# --- Test ---
client = TestClient(app, raise_server_exceptions=False)

# Normal response
print(f"OK: {client.get('/ok').json()}")

# HTTPException -> specific handler
resp = client.get("/not-found")
print(f"404: {resp.json()['error']['code']}")

# ZeroDivisionError -> global handler
resp = client.get("/crash")
print(f"500: {resp.status_code} {resp.json()['error']['code']}")
print(f"Has request_id: {'request_id' in resp.json()['error']}")

# KeyError -> global handler
resp = client.get("/key-error")
print(f"KeyError: {resp.status_code} {resp.json()['error']['code']}")

# Expected Output:
# OK: {'status': 'ok'}
# 404: HTTP_404
# ERROR: [<id>] Unhandled ZeroDivisionError on GET /crash: division by zero
# 500: 500 INTERNAL_ERROR
# Has request_id: True
# ERROR: [<id>] Unhandled KeyError on GET /key-error: 'missing_key'
# KeyError: 500 INTERNAL_ERROR
